sys_script.script:
(function executeRule(current, previous /*null when async*/) {

    // 1. Enforce Mon/Wed/Fri only
    var startDt = new GlideDateTime(current.getValue('start_time'));
    var dow = startDt.getDayOfWeekLocalTime(); // 1=Sun,2=Mon,3=Tue,4=Wed,5=Thu,6=Fri,7=Sat
    if (dow !== 2 && dow !== 4 && dow !== 6) {
        current.setAbortAction(true);
        gs.addErrorMessage('Lessons can only be booked on Monday, Wednesday, or Friday.');
        return;
    }

    var availability = new x_608645_my_comp_0.LessonAvailability();

    // 2. Enforce 1 lesson/week per student
    if (availability.hasStudentBookedThisWeek(current.getValue('student'))) {
        current.setAbortAction(true);
        gs.addErrorMessage('You already have a lesson booked this week. Maximum one lesson per week is allowed.');
        return;
    }

    // 3. Enforce max 3 concurrent bookings (3 teachers)
    if (!availability.isSlotAvailable(current.getValue('start_time'), current.getValue('end_time'))) {
        current.setAbortAction(true);
        gs.addErrorMessage('This time slot is fully booked. All 3 teachers are occupied. Please choose another slot.');
    }

})(current, previous);
